import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input, but in a real scenario this would come from user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Sanitizing and escaping user input before using it in output
